Javascript.validate:
var val = Services.getValue(AmtPaidToClaimant.dataBinding);
var err = validateCurrencyValue(val, 99999999.99);
if( null == err )
{	Services.setValue(AmtPaidToClaimant.dataBinding, WPU.formatToTwoDP(val));
}
return err;

